'use strict';
// Concatenate src/widget/*.js (in deterministic dependency order) + the
// remaining content.js into dist/content.js. Mirror of
// scripts/build-solver-bundle.js — the extension content script needs a
// single concatenated file because the browser loads it via
// manifest.json's content_scripts.js entry (no module system).

const fs = require('fs');
const path = require('path');

const WIDGET_FILES = [
  // State (detectedGrid, undo/redo, widget prefs) — no dependencies.
  'state.js',
  // Solver Worker proxy + the per-puzzle modules (which reference
  // `runSolve` from worker.js in their hooks but only at call time).
  'worker.js',
  'cache.js',
  'galaxies-hint.js',
  // hint.js declares getHint, which calls into per-puzzle hooks via
  // PUZZLES. Function bodies are resolved at call time, so it's safe
  // to declare hint.js before puzzles/index.js — the listener fires
  // getHint only after the whole bundle has loaded.
  'hint.js',
  'preview.js',
  'puzzles/nonogram.js',
  'puzzles/binairo.js',
  'puzzles/hitori.js',
  'puzzles/kakurasu.js',
  'puzzles/kurodoko.js',
  'puzzles/mosaic.js',
  'puzzles/norinori.js',
  'puzzles/nurikabe.js',
  'puzzles/heyawake.js',
  'puzzles/yinyang.js',
  'puzzles/aquarium.js',
  'puzzles/shikaku.js',
  'puzzles/hashi.js',
  'puzzles/slitherlink.js',
  'puzzles/galaxies.js',
  // Aggregates the per-puzzle const declarations into the PUZZLES map.
  // Must come after all puzzles/<type>.js files.
  'puzzles/index.js',
  // The widget shell. References PUZZLES at runtime; safe after
  // puzzles/index.js.
  'widget.js',
  // detectPuzzle / readGridState / applySolution / solveExtraData /
  // handleHistory — used by listener.js and widget.js. Function bodies,
  // so call-time refs are fine.
  'handlers.js',
  // chrome.runtime.onMessage listener + DOM-ready bootstrap. Last so
  // every symbol the listener/bootstrap touches is already declared.
  'listener.js',
];

const EXPORT_RE =
  /\n\s*if\s*\(\s*typeof\s+module[\s\S]*?module\.exports\s*=\s*\{[\s\S]*?\}\s*;?\s*\}\s*$/;

const root = path.join(__dirname, '..');
const widgetDir = path.join(root, 'src', 'widget');

function buildContentBundle() {
  const parts = [
    "'use strict';",
    "// Generated by scripts/build-content-bundle.js — do not edit by hand.",
    "",
  ];
  for (const file of WIDGET_FILES) {
    const fullPath = path.join(widgetDir, file);
    if (!fs.existsSync(fullPath)) continue;
    let body = fs.readFileSync(fullPath, 'utf8');
    body = body.replace(/^\s*'use strict';\s*\n/, '');
    body = body.replace(EXPORT_RE, '');
    parts.push(`// ── src/widget/${file} ──`);
    parts.push(body.trim());
    parts.push("");
  }
  const contentBody = fs.readFileSync(path.join(root, 'content.js'), 'utf8')
    .replace(/^\s*'use strict';\s*module\.exports\s*=\s*require\([^)]*\)\s*;\s*$/m, '');
  parts.push('// ── content.js ──');
  parts.push(contentBody.trim());
  parts.push('');
  return parts.join('\n');
}

if (require.main === module) {
  const outDir = path.join(root, 'dist');
  fs.mkdirSync(outDir, { recursive: true });
  fs.writeFileSync(path.join(outDir, 'content.js'), buildContentBundle());
  console.log('Wrote dist/content.js');
}

module.exports = { buildContentBundle };
